module sync_down_counter_4bit(
    input clk,
    input rst_n,
    input en,
    output reg [3:0] count
);

    reg [3:0] cnt_reg;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            cnt_reg <= 4'b1111;
        end else if (en) begin
            cnt_reg <= cnt_reg - 1;
        end
    end

    assign count = cnt_reg;

endmodule
